Question 1

zero_sum &lt;- function(num_vec){
  counter &lt;- 0

  for (i in seq_along(num_vec)){
    if (num_vec[i] == 0){
      counter &lt;- counter + 1
    }

  }
  return(counter)
}

zero_vec &lt;- sample(0:10, 100, replace = TRUE)
num_zero &lt;- zero_sum(zero_vec)
print(num_zero)

