row_col_mat &lt;- function(x = 3, y = 4){
  r_vec &lt;- c(1:x)
  c_vec &lt;- c(1:y)
  mat &lt;- matrix(nrow = x, ncol = y) # changed n_row -&gt; nrow


  for (i in r_vec){
    for (j in c_vec){
      mat[i,j] &lt;- r_vec[i] * c_vec[j]
    }
  }
  return(mat) 
}
print(row_col_mat())

